import{_ as s,o as n,c as t,ag as p}from"./chunks/framework.DXGyWiRo.js";const u=JSON.parse('{"title":"1.4 集合的运算","description":"","frontmatter":{},"headers":[],"relativePath":"notes/gaozhong/gaoyi/chapter01-sets/1-4-集合的运算.md","filePath":"notes/gaozhong/gaoyi/chapter01-sets/1-4-集合的运算.md"}'),e={name:"notes/gaozhong/gaoyi/chapter01-sets/1-4-集合的运算.md"};function l(c,a,o,i,$,r){return n(),t("div",null,[...a[0]||(a[0]=[p(`<h1 id="_1-4-集合的运算" tabindex="-1">1.4 集合的运算 <a class="header-anchor" href="#_1-4-集合的运算" aria-label="Permalink to &quot;1.4 集合的运算&quot;">​</a></h1><h2 id="一、交集" tabindex="-1">一、交集 <a class="header-anchor" href="#一、交集" aria-label="Permalink to &quot;一、交集&quot;">​</a></h2><p>由属于集合 $A$ <strong>且</strong> 属于集合 $B$ 的所有元素组成的集合，称为 $A$ 与 $B$ 的<strong>交集</strong>，记作 $A \\cap B$。</p><p>$$A \\cap B = {x \\mid x \\in A \\text{ 且 } x \\in B}$$</p><details class="details custom-block"><summary>点击展开图示</summary><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>    ╭───────────────────╮</span></span>
<span class="line"><span>   ╱    A                ╲</span></span>
<span class="line"><span>  │   ╭────────╮         │</span></span>
<span class="line"><span>  │  ╱ (A∩B)   ╲         │</span></span>
<span class="line"><span>  │  │ ■■■■■■   │         │</span></span>
<span class="line"><span>  │  ╲  (交集)  ╱          │</span></span>
<span class="line"><span>  │   ╰────────╯         │</span></span>
<span class="line"><span>  ╰──────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  A∩B：用■标出的阴影区域</span></span></code></pre></div></details><div class="tip custom-block"><p class="custom-block-title">记忆口诀</p><p>&quot;交&quot;就是两者<strong>都有</strong>的元素。</p></div><p><strong>运算律：</strong></p><ul><li>$A \\cap A = A$</li><li>$A \\cap \\varnothing = \\varnothing$</li><li>$A \\cap B = B \\cap A$（交换律）</li><li>$(A \\cap B) \\cap C = A \\cap (B \\cap C)$（结合律）</li></ul><h2 id="二、并集" tabindex="-1">二、并集 <a class="header-anchor" href="#二、并集" aria-label="Permalink to &quot;二、并集&quot;">​</a></h2><p>由属于集合 $A$ <strong>或</strong> 属于集合 $B$ 的所有元素组成的集合，称为 $A$ 与 $B$ 的<strong>并集</strong>，记作 $A \\cup B$。</p><p>$$A \\cup B = {x \\mid x \\in A \\text{ 或 } x \\in B}$$</p><details class="details custom-block"><summary>点击展开图示</summary><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>    ╭───────────────────╮</span></span>
<span class="line"><span>   ╱    A                ╲</span></span>
<span class="line"><span>  │   ╭────────╮         │</span></span>
<span class="line"><span>  │  ╱ ■■■■■■■■ ╲         │</span></span>
<span class="line"><span>  │  │ ■■■■■■   │         │</span></span>
<span class="line"><span>  │  ╲ ■■■■■■■■ ╱          │</span></span>
<span class="line"><span>  │   ╰────────╯         │</span></span>
<span class="line"><span>  ╰──────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  A∪B：A和B的所有区域</span></span></code></pre></div></details><div class="tip custom-block"><p class="custom-block-title">记忆口诀</p><p>&quot;并&quot;就是两者<strong>合在一起</strong>的所有元素（去重）。</p></div><p><strong>运算律：</strong></p><ul><li>$A \\cup A = A$</li><li>$A \\cup \\varnothing = A$</li><li>$A \\cup B = B \\cup A$（交换律）</li><li>$(A \\cup B) \\cup C = A \\cup (B \\cup C)$（结合律）</li><li>$A \\cap (B \\cup C) = (A \\cap B) \\cup (A \\cap C)$（分配律）</li><li>$A \\cup (B \\cap C) = (A \\cup B) \\cap (A \\cup C)$（分配律）</li></ul><h2 id="三、补集" tabindex="-1">三、补集 <a class="header-anchor" href="#三、补集" aria-label="Permalink to &quot;三、补集&quot;">​</a></h2><p>在研究某个问题时，如果集合 $I$ 包含了我们所考虑的所有元素，则称 $I$ 为<strong>全集</strong>。</p><p>对于全集 $I$ 中的任意集合 $A$，$A$ 的<strong>补集</strong>（或<strong>余集</strong>）定义为：</p><p>$$\\complement_I A = {x \\in I \\mid x \\notin A}$$</p><div class="tip custom-block"><p class="custom-block-title">通俗理解</p><p>补集就是&quot;在全集里把 $A$ 挖掉&quot;剩下的部分。</p></div><details class="details custom-block"><summary>点击展开图示</summary><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>    ╭───────────────────╮</span></span>
<span class="line"><span>   ╱       I (全集)       ╲</span></span>
<span class="line"><span>  │                       │</span></span>
<span class="line"><span>  │   ╭──────────╮       │</span></span>
<span class="line"><span>  │  ╱   A (已挖)  ╲      │</span></span>
<span class="line"><span>  │  │             │      │</span></span>
<span class="line"><span>  │  ╲             ╱      │</span></span>
<span class="line"><span>  │   ╰──────────╯       │</span></span>
<span class="line"><span>  │   （A以外的区域）      │</span></span>
<span class="line"><span>  ╰──────────────────────╯</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  补集 = 全集 I 中不属于 A 的部分</span></span></code></pre></div></details><h2 id="四、交、并、补运算的综合" tabindex="-1">四、交、并、补运算的综合 <a class="header-anchor" href="#四、交、并、补运算的综合" aria-label="Permalink to &quot;四、交、并、补运算的综合&quot;">​</a></h2><table tabindex="0"><thead><tr><th>运算</th><th>定义</th><th>关键词</th></tr></thead><tbody><tr><td>交集 $A \\cap B$</td><td>既在 $A$ 又在 $B$</td><td>&quot;且&quot;、&quot;and&quot;</td></tr><tr><td>并集 $A \\cup B$</td><td>在 $A$ 或 $B$ 或两者</td><td>&quot;或&quot;、&quot;or&quot;</td></tr><tr><td>补集 $\\complement A$</td><td>不在 $A$ 中</td><td>&quot;非&quot;、&quot;不是&quot;</td></tr></tbody></table><h2 id="五、常用结论" tabindex="-1">五、常用结论 <a class="header-anchor" href="#五、常用结论" aria-label="Permalink to &quot;五、常用结论&quot;">​</a></h2><table tabindex="0"><thead><tr><th>公式</th><th>说明</th></tr></thead><tbody><tr><td>$A \\cap B \\subseteq A \\subseteq A \\cup B$</td><td>—</td></tr><tr><td>$A \\cap B \\subseteq B \\subseteq A \\cup B$</td><td>—</td></tr><tr><td>$A \\cap B = \\varnothing$</td><td>$A$ 与 $B$ 无公共元素</td></tr><tr><td>$A \\cup B = I$ 且 $A \\cap B = \\varnothing$</td><td>$B$ 是 $A$ 的补集</td></tr><tr><td>$\\complement(\\complement A) = A$</td><td>补集的补集是自身</td></tr><tr><td>$\\complement(A \\cup B) = \\complement A \\cap \\complement B$</td><td>德·摩根定律</td></tr><tr><td>$\\complement(A \\cap B) = \\complement A \\cup \\complement B$</td><td>德·摩根定律</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">德·摩根定律（重要）</p><ul><li>$\\overline{A \\cup B} = \\overline{A} \\cap \\overline{B}$</li><li>$\\overline{A \\cap B} = \\overline{A} \\cup \\overline{B}$</li></ul><p>口诀：<strong>加号变乘号，开门变关门</strong>。</p></div><h2 id="六、例题" tabindex="-1">六、例题 <a class="header-anchor" href="#六、例题" aria-label="Permalink to &quot;六、例题&quot;">​</a></h2><details class="details custom-block"><summary>点击查看例题</summary><p><strong>例1：</strong> 设 $A = {1, 2, 3}$，$B = {2, 4, 6}$，求 $A \\cap B$、$A \\cup B$。</p><p><strong>解析：</strong></p><p>$A \\cap B = {2}$（只有 2 是两者共有的）</p><p>$A \\cup B = {1, 2, 3, 4, 6}$（合并，去重）</p><hr><p><strong>例2：</strong> 设全集 $I = {1, 2, 3, 4, 5}$，$A = {1, 3}$，求 $\\complement_I A$。</p><p><strong>解析：</strong></p><p>$\\complement_I A = {2, 4, 5}$（在全集 $I$ 中去掉 1 和 3）</p><hr><p><strong>例3：</strong> 已知 $A = {x \\mid x &gt; 0}$，$B = {x \\mid x &lt; 3}$，求 $A \\cap B$、$A \\cup B$。</p><p><strong>解析：</strong></p><p>$A \\cap B = {x \\mid 0 &lt; x &lt; 3}$，即 $(0, 3)$</p><p>$A \\cup B = {x \\mid x &gt; 0 \\text{ 或 } x &lt; 3}$，即全体实数 $\\mathbb{R}$（因为 $x &gt; 0$ 或 $x &lt; 3$ 覆盖了所有实数）</p><hr><p><strong>例4：</strong> 证明德·摩根定律：$\\complement(A \\cup B) = \\complement A \\cap \\complement B$。</p><p><strong>解析：</strong></p><p>设 $x \\in \\complement(A \\cup B)$，则 $x \\notin A \\cup B$，即 $x \\notin A$ 且 $x \\notin B$。</p><p>所以 $x \\in \\complement A$ 且 $x \\in \\complement B$，即 $x \\in \\complement A \\cap \\complement B$。</p><p>故 $\\complement(A \\cup B) \\subseteq \\complement A \\cap \\complement B$。</p><p>同理可证反向包含，故两边相等。证毕。</p></details>`,28)])])}const m=s(e,[["render",l]]);export{u as __pageData,m as default};
